from heapq import heappush, heappop
from collections import defaultdict
from functools import lru_cache

mod = 10**9 + 7

def countRestrictedPaths(n, edges):
    graph = defaultdict(list)
    for u, v, w in edges:
        graph[u].append((v, w))
        graph[v].append((u, w))

    dist = [float('inf')] * (n + 1)
    dist[n] = 0
    pq = [(0, n)] # (distance, node)

    while pq:
        d, u = heappop(pq)
        if d != dist[u]:
            continue
        for v, w in graph[u]:
            if dist[u] + w < dist[v]:
                dist[v] = dist[u] + w
                heappush(pq, (dist[v], v))

    @lru_cache(None)
    def dfs(u):
        if u == n:
            return 1
        ans = 0
        for v, _ in graph[u]:
            if dist[v] < dist[u]:
                ans = (ans + dfs(v)) % mod
        return ans

    return dfs(1)
```

    1. Create the adjacency list graph representation of the input.
2. Run Dijkstra's algorithm to find the shortest path from node n to every other node in the graph.
3. Use a variation of DFS with memoization (in this case, the DFS function is called dfs) to count the number of restricted paths from node 1 to node n.
   a. In the dfs function, iterate over each neighbor of the current node u.
   b. If the distance of the neighbor is less than the distance of the current node, call the DFS function recursively on the neighbor and add the value to the answer.
   c. Make sure to take the result modulo 10^9 + 7 to keep the answer from overflowing.
4. Call the dfs function starting from node 1 to get the final result.

