function countRestrictedPaths(n, edges) {
    let graph = new Array(n + 1).fill(null).map(() => []);
    let dist = new Array(n + 1).fill(Number.MAX_VALUE);

    edges.forEach(([u, v, w]) => {
        graph[u].push([v, w]);
        graph[v].push([u, w]);
    });

    let pq = [[0, n]]; // [distance, node]
    dist[n] = 0;

    while (pq.length !== 0) {
        pq.sort((a, b) => a[0] - b[0]);
        let [d, u] = pq.pop();
        if (d !== dist[u]) continue;

        graph[u].forEach(([v, w]) => {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push([dist[v], v]);
            }
        });
    }

    let dp = new Array(n + 1).fill(-1);

    function dfs(u) {
        if (u === n) return 1;
        if (dp[u] !== -1) return dp[u];
        let ans = 0;
        graph[u].forEach(([v, _]) => {
            if (dist[v] < dist[u]) {
                ans = (ans + dfs(v)) % mod;
            }
        });
        dp[u] = ans;
        return ans;
    }

    return dfs(1);
}
