import java.util.*;

class Solution {
    static final int mod = 1000000007;

    public int countRestrictedPaths(int n, int[][] edges) {
        List<List<Pair>> graph = new ArrayList<>();
        for (int i = 0; i <= n; i++) {
            graph.add(new ArrayList<>());
        }

        for (int[] edge : edges) {
            int u = edge[0], v = edge[1], weight = edge[2];
            graph.get(u).add(new Pair(v, weight));
            graph.get(v).add(new Pair(u, weight));
        }

        long[] dist = new long[n + 1];
        Arrays.fill(dist, Long.MAX_VALUE);

        PriorityQueue<Pair> pq = new PriorityQueue<>((a, b) -> Long.compare(a.weight, b.weight));
        pq.offer(new Pair(n, 0));
        dist[n] = 0;

        while (!pq.isEmpty()) {
            Pair p = pq.poll();
            int u = p.node;
            long d = p.weight;

            if (d != dist[u]) continue;

            for (Pair to : graph.get(u)) {
                int v = to.node;
                long w = to.weight;
                if (dist[u] + w < dist[v]) {
                    dist[v] = dist[u] + w;
                    pq.offer(new Pair(v, dist[v]));
                }
            }
        }

        int[] dp = new int[n + 1];
        Arrays.fill(dp, -1);
        return dfs(graph, dist, dp, 1);
    }

    int dfs(List<List<Pair>> graph, long[] dist, int[] dp, int u) {
        int n = dist.length - 1;
        if (u == n) return 1;
        if (dp[u] != -1) return dp[u];
        int ans = 0;
        for (Pair to : graph.get(u)) {
            int v = to.node;
            if (dist[v] < dist[u]) {
                ans = (int) ((ans + (long) dfs(graph, dist, dp, v)) % mod);
            }
        }
        dp[u] = ans;
        return ans;
    }

    static class Pair {
        int node;
        long weight;

        Pair(int node, long weight) {
            this.node = node;
            this.weight = weight;
        }
    }
}
